mapper.select:
SELECT
    SMS_SEND_DATE
FROM MSP_GIFT_PRMT_CUSTOMER@DL_MSP
WHERE 1=1
AND SEND_YN = 'Y'
AND PRMT_ID = #{prmtId}
AND SUBSCRIBER_NO = #{phone}
AND SUB_LINK_NAME = #{name}

mapper.update:
UPDATE MSP_GIFT_PRMT_CUSTOMER@DL_MSP SET
    GIFT_REGST_DATE = TO_CHAR(SYSDATE,'YYYYMMDD')
    , MNG_NM = #{name}
    , TEL_FN1 = #{telFn1}
    , TEL_MN1 = #{telMn1}
    , TEL_RN1 = #{telRn1}
    , POST = #{post}
    , ADDR = #{addr}
    , ADDR_DTL = #{addrDtl}
WHERE 1=1
AND PRMT_ID = #{prmtId}
AND CONTRACT_NUM = #{contractNum}
AND SUBSCRIBER_NO = #{phone}

mapper.select:
SELECT
     TAX_NO
   , TEL_NO
   , USER_NM
   , TAX_RECV_TIME
FROM MSP_TAX_SMS_SEND_LIST@DL_MSP
WHERE 1=1

    AND TAX_NO = #{taxNo}


    AND USER_NM = #{userNm}


    AND TEL_NO = #{telNO}

mapper.update:
UPDATE MSP_TAX_SMS_SEND_LIST@DL_MSP SET
   TAX_ADR_ZIP = #{taxAdrZip}
   , TAX_ADR_PRIMARY_LN = #{taxAdrPrimaryLn}
   , TAX_ADR_SECONDARY_LN = #{taxAdrSecondaryLn}
   , TAX_RECV_TIME = SYSDATE
WHERE 1=1
AND TEL_NO = #{telNO}
AND USER_NM = #{userNm}
AND TAX_NO = #{taxNo}
